import { Router } from 'express';
import { createCourseExam, createExamSchedule, getCourseExamById, getCourseExams, getExamResults, getExamSchedules, submitExamResult, } from '../controllers/exam.controller';
const router = Router();
router.post('/schedules', createExamSchedule);
router.get('/schedules', getExamSchedules);
router.post('/results', submitExamResult);
router.get('/results', getExamResults);
router.post('/course-exams', createCourseExam);
router.get('/course-exams', getCourseExams);
router.get('/course-exams/:id', getCourseExamById);
export default router;
